class Solution(object):
    def zigzagTraversal(self, grid):
        cells = []
        for i, row in enumerate(grid):
            if i % 2 == 0:
                cells.extend(row)
            else:
                cells.extend(reversed(row))
        return [cells[i] for i in range(0, len(cells), 2)]
